import React from 'react';
import { motion } from 'framer-motion';

const Navbar = () => {
  return (
    <motion.nav 
      initial={{ y: -100 }}
      animate={{ y: 0 }}
      className="fixed top-4 left-1/2 -translate-x-1/2 w-[90%] z-50 px-8 py-4 bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl flex justify-between items-center shadow-2xl"
    >
      <div className="text-2xl font-black bg-gradient-to-r from-purple-400 to-pink-600 bg-clip-text text-transparent">
        TASK.IO
      </div>
      <div className="flex gap-6 text-white font-medium">
        <a href="#" className="hover:text-purple-400 transition-all">Dashboard</a>
        <a href="#" className="hover:text-purple-400 transition-all">My Tasks</a>
        <button className="bg-purple-600 px-5 py-2 rounded-xl hover:shadow-[0_0_20px_rgba(147,51,234,0.5)] transition-all">
          Logout
        </button>
      </div>
    </motion.nav>
  );
};

export default Navbar;
